import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import EmployeeLayout from '../components/EmployeeLayout';
import pageStyles from '../pages/PageStyle2.module.css';
import insertBookStyles from './InsertBookPage.module.css';

function InsertBookPage() {
  const [formData, setFormData] = useState({
    seriesTitle: '',
    seriesStartDate: '',
    seriesEndDate: '',
    publisher: '',
    issueNumber: '',
    releaseDate: '',
    coverArt: '',
  });
  const [tags, setTags] = useState([]);
  const [currentTag, setCurrentTag] = useState('');
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');
  const navigate = useNavigate();

  const { seriesTitle, seriesStartDate, seriesEndDate, publisher, issueNumber, releaseDate, coverArt } = formData;

  const onChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleAddTag = () => {
    if (currentTag && !tags.includes(currentTag)) {
      setTags([...tags, currentTag]);
      setCurrentTag('');
    }
  };

  const handleRemoveTag = (tagToRemove) => {
    setTags(tags.filter(tag => tag !== tagToRemove));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setMessage('');

    try {
      const userInfo = JSON.parse(localStorage.getItem('userInfo'));
      const config = {
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${userInfo.token}`,
        },
      };

      const bookData = { ...formData, tags };
      if (!bookData.seriesEndDate) {
        delete bookData.seriesEndDate; // Don't send empty string for optional date
      }

      await axios.post('/api/books', bookData, config);
      setMessage('Book added successfully!');
      setTimeout(() => navigate('/dashempl'), 2000);
    } catch (err) {
      setError(err.response?.data?.message || 'An error occurred');
    }
  };

  return (
    <EmployeeLayout title="Add a Book">
      <div>
        {message && <p style={{ color: 'green' }}>{message}</p>}
        {error && <p className={pageStyles.error}>{error}</p>}
        <form onSubmit={handleSubmit}>
          <div>
            <label>Series Title*:</label>
            <input type="text" name="seriesTitle" value={seriesTitle} onChange={onChange} required />
          </div>
          <div>
            <label>Series Start Date*:</label>
            <input type="date" name="seriesStartDate" value={seriesStartDate} onChange={onChange} required />
          </div>
          <div>
            <label>Series End Date:</label>
            <input type="date" name="seriesEndDate" value={seriesEndDate} onChange={onChange} />
          </div>
          <div>
            <label>Publisher*:</label>
            <input type="text" name="publisher" value={publisher} onChange={onChange} required />
          </div>
          <div>
            <label>Issue Number*:</label>
            <input type="number" name="issueNumber" value={issueNumber} onChange={onChange} required />
          </div>
          <div>
            <label>Release Date*:</label>
            <input type="date" name="releaseDate" value={releaseDate} onChange={onChange} required />
          </div>
          <div>
            <label>Cover Art Path:</label>
            <input type="text" name="coverArt" value={coverArt} onChange={onChange} />
          </div>
          <div>
            <label>Tags:</label>
            <input
              type="text"
              value={currentTag}
              onChange={(e) => setCurrentTag(e.target.value)}
              onKeyDown={(e) => { if (e.key === 'Enter') { e.preventDefault(); handleAddTag(); } }}
            />
            <button type="button" onClick={handleAddTag}>Add Tag</button>
            <div>
              {tags.map(tag => (
                <span key={tag} style={{ border: '1px solid #ccc', borderRadius: '3px', padding: '2px 5px', marginRight: '5px' }}>
                  {tag}
                  <button type="button" onClick={() => handleRemoveTag(tag)} style={{ marginLeft: '5px', border: 'none', background: 'transparent', color: 'red', cursor: 'pointer' }}>x</button>
                </span>
              ))}
            </div>
          </div>
          <button type="submit">Insert Book</button>
          <button type="button" onClick={() => navigate('/dashempl')}>Cancel</button>
        </form>
      </div>
    </EmployeeLayout>
  );
}

export default InsertBookPage;
